        self.control_sequence += 1;
        return self.control_sequence;
    }

    fn finishControlCommand(ctrl: *control.ControlClient, saw_error: bool, exit_code: u16, number: u32) void {
        if (saw_error or exit_code != 0) {
            ctrl.sendError(0, number, 0);
