pub fn terminalProbeKindFromInt(raw: u8) !TerminalProbeKind {
    return switch (raw) {
        @intFromEnum(TerminalProbeKind.foreground_color) => .foreground_color,
        @intFromEnum(TerminalProbeKind.background_color) => .background_color,
        @intFromEnum(TerminalProbeKind.cursor_color) => .cursor_color,
        @intFromEnum(TerminalProbeKind.primary_device_attributes) => .primary_device_attributes,
        @intFromEnum(TerminalProbeKind.terminal_version) => .terminal_version,
        else => error.InvalidTerminalProbeKind,
    };
}

pub fn terminalProbeStatusFromInt(raw: u8) !TerminalProbeStatus {
    return switch (raw) {
        @intFromEnum(TerminalProbeStatus.complete) => .complete,
        @intFromEnum(TerminalProbeStatus.timeout) => .timeout,
        @intFromEnum(TerminalProbeStatus.unsupported) => .unsupported,
        else => error.InvalidTerminalProbeStatus,
    };
}

pub fn terminalProbeRequestBytes(kind: TerminalProbeKind) []const u8 {
    return switch (kind) {
        .foreground_color => "\x1b]10;?\x1b\\",
        .background_color => "\x1b]11;?\x1b\\",
        .cursor_color => "\x1b]12;?\x1b\\",
        .primary_device_attributes => "\x1b[c",
        .terminal_version => "\x1b[>0q",
    };
}

pub fn encodeTerminalProbeRequest(
    alloc: std.mem.Allocator,
    request_id: u32,
    owner_client_id: u64,
    probe_kind: TerminalProbeKind,
    bytes: []const u8,
) ![]u8 {
    if (bytes.len + @sizeOf(TerminalProbeRequestHeader) > max_payload) return error.PayloadTooLarge;

    const payload = try alloc.alloc(u8, @sizeOf(TerminalProbeRequestHeader) + bytes.len);
    errdefer alloc.free(payload);

    const header = TerminalProbeRequestHeader{
        .request_id = request_id,
        .owner_client_id = owner_client_id,
        .probe_kind = @intFromEnum(probe_kind),
        .reserved = .{ 0, 0, 0 },
        .bytes_len = @intCast(bytes.len),
    };
    @memcpy(payload[0..@sizeOf(TerminalProbeRequestHeader)], std.mem.asBytes(&header));
    @memcpy(payload[@sizeOf(TerminalProbeRequestHeader)..], bytes);
    return payload;
}

pub fn decodeTerminalProbeRequest(payload: []const u8) !TerminalProbeRequest {
    if (payload.len < @sizeOf(TerminalProbeRequestHeader)) return error.InvalidTerminalProbeRequest;
    const header: *const TerminalProbeRequestHeader = @ptrCast(@alignCast(payload.ptr));
    const probe_kind = try terminalProbeKindFromInt(header.probe_kind);
    const bytes_start = @sizeOf(TerminalProbeRequestHeader);
    const bytes_end = bytes_start + header.bytes_len;
    if (bytes_end > payload.len) return error.InvalidTerminalProbeRequest;
    return .{
        .request_id = header.request_id,
        .owner_client_id = header.owner_client_id,
        .probe_kind = probe_kind,
        .bytes = payload[bytes_start..bytes_end],
    };
}

